<template><div class="training-page"><section class="training-brief"><div><p class="eyebrow">AI 1-on-1</p><h2>{{modeConfig.title}}</h2><p>{{modeConfig.summary}}</p></div><div class="brief-grid"><div><span>Course</span><strong>{{trainingContext.course}}</strong></div><div><span>Phase</span><strong>{{trainingContext.phase}}</strong></div><div class="mode-switch-cell"><div class="mode-switch"><button :class="{active:currentMode==='tutor'}" @click="switchMode('tutor')">Tutor</button><button :class="{active:currentMode==='interview'}" @click="switchMode('interview')">Challenge</button></div></div></div></section><section class="video-session"><div class="ai-video-card"><div class="video-header"><span>{{modeConfig.videoRole}}</span><strong>{{modeConfig.videoName}}</strong></div><div class="ai-avatar-stage"><iframe class="live2d-tutor-frame" src="/live2d/yili/index.html" frameborder="0" scrolling="no"></iframe></div><div class="current-question"><span>Topic</span><strong>{{currentQuestion||'Ask or start a challenge'}}</strong></div></div><div class="chat-area"><div v-for="m in messages" :key="m.id" class="message-row"><div class="message-content" v-html="renderMarkdown(m.content)"></div></div><div class="input-row"><el-input v-model="inputText" placeholder="Enter your message..." @keyup.enter.native="sendText"></el-input><el-button type="primary" @click="sendText">Send</el-button></div></div></section></div></template><script>import axios from 'axios';import DOMPurify from 'dompurify';import {getCurrentUser} from '@/utils/learningPersonalization';export default{name:'AiInterview',data(){return{inputText:'',loading:false,currentMode:'tutor',messages:[],currentUser:{}},live2dApp:null,live2dModel:null},computed:{modeConfig(){return this.currentMode==='tutor'?{title:'1-on-1 Tutoring',summary:'AI teacher answers questions, gives hints, and guides learning.',videoRole:'AI Tutor',videoName:'Yili',icon:'👩‍🏫'}:{title:'Knowledge Challenge',summary:'AI asks questions, evaluates answers, and tracks progress.',videoRole:'AI Examiner',videoName:'Yili',icon:'🎓'}},trainingContext(){return{course:'AI Basics',phase:'Beginner to Advanced'}},currentQuestion(){return this.messages.length?this.messages[this.messages.length-1].content.slice(0,50):''}},created(){this.currentUser=getCurrentUser()},mounted(){},methods:{switchMode(m){this.currentMode=m;this.messages=[]},renderMarkdown(t){if(!t)return'';const h=t.replace(/\*\*(.+?)\*\*/g,'<strong>$1</strong>').replace(/\n/g,'<br>');return DOMPurify.sanitize(h,{ALLOWED_TAGS:['strong','br'],ALLOWED_ATTR:[]})},async sendText(){const t=this.inputText.trim();if(!t||this.loading)return;this.inputText='';this.messages.push({id:Date.now(),role:'user',content:t});this.loading=true;try{const r=await axios.post('/api/learning-agent/chat',{agentType:this.currentMode==='tutor'?'training':'evaluation',message:t});this.messages.push({id:Date.now(),role:'assistant',content:r.data.content,confidence:r.data.confidence,mode:r.data.mode})}catch(e){this.messages.push({id:Date.now(),role:'assistant',content:'AI tutor is thinking...'})}this.loading=false}}}</script><style scoped>.live2d-tutor-frame{width:100%;height:320px;border:none;background:transparent}</style>